(1, 1, 'Apple', 'iPhone 16 128GB', 'Apple iPhone 16', 'A current-generation iPhone with Apple Intelligence support, a durable aluminum design, Camera Control, fast A18 performance, and a balanced camera system for everyday photos and video.', JSON_ARRAY('6.1-inch Super Retina XDR display', 'A18 chip built for Apple Intelligence', '48MP Fusion camera', 'USB-C charging', 'Emergency SOS via satellite'), JSON_OBJECT('Display','6.1-inch Super Retina XDR OLED','Processor','Apple A18','Storage','128GB','Rear camera','48MP Fusion + Ultra Wide','Charging','USB-C','Best for','Everyday flagship phone buyers'), 799.00, 829.00, 4.8, 1842, 18, 'https://images.unsplash.com/photo-1695048133142-1a20484d2569?auto=format&fit=crop&w=1000&q=80', 'https://www.apple.com/iphone-16/specs/', '1-year limited manufacturer warranty', 'Free 2-day demo shipping'),
(2, 1, 'Samsung', 'SM-S938U', 'Samsung Galaxy S25 Ultra', 'Premium Android flagship with a large bright display, Galaxy AI features, integrated S Pen, pro-grade zoom camera system, and strong multitasking performance.', JSON_ARRAY('Galaxy AI ready', 'Built-in S Pen', 'Large AMOLED display', 'Pro-grade zoom camera', 'Titanium-style premium build'), JSON_OBJECT('Display','6.9-inch QHD+ AMOLED class','Processor','Snapdragon 8 Elite for Galaxy class','Storage','256GB','Rear camera','200MP wide with telephoto system','Charging','USB-C fast charging','Best for','Power users and mobile photography'), 1299.99, 1419.99, 4.7, 965, 10, 'https://images.unsplash.com/photo-1610945265064-0e34e5519bbf?auto=format&fit=crop&w=1000&q=80', 'https://www.samsung.com/us/smartphones/galaxy-s25-ultra/', '1-year limited manufacturer warranty', 'Ships in 1 business day'),
(3, 1, 'Google', 'Pixel 9 Pro 128GB', 'Google Pixel 9 Pro', 'Compact pro Pixel phone with Google Tensor performance, advanced AI photo editing, a bright Super Actua display, and long software support.', JSON_ARRAY('Google Tensor G4 class chip', 'Super Actua display', 'Pro triple camera system', '7 years of updates', 'Gemini-powered Pixel features'), JSON_OBJECT('Display','6.3-inch LTPO OLED class','Processor','Google Tensor G4','Storage','128GB','Rear camera','Triple pro camera system','Security','Titan M2 security chip','Best for','AI photos and clean Android'), 999.00, 1099.00, 4.6, 741, 13, 'https://images.unsplash.com/photo-1598327105666-5b89351aff97?auto=format&fit=crop&w=1000&q=80', 'https://store.google.com/us/product/pixel_9_pro_specs', '1-year limited manufacturer warranty', 'Pickup available today'),
(4, 1, 'OnePlus', 'CPH2655', 'OnePlus 13', 'Fast Android phone focused on speed, battery life, smooth display performance, and rapid charging for heavy daily users.', JSON_ARRAY('Smooth high-refresh AMOLED display', 'Large battery', 'Fast charging support', 'Flagship-class processor', 'Triple camera system'), JSON_OBJECT('Display','6.8-inch AMOLED class','Processor','Snapdragon 8 Elite class','Storage','256GB','Battery','Large all-day battery','Charging','Fast wired charging','Best for','Performance per dollar'), 899.99, 949.99, 4.5, 318, 16, 'https://images.unsplash.com/photo-1592899677977-9c10ca588bbd?auto=format&fit=crop&w=1000&q=80', 'https://www.oneplus.com/us/13', '1-year limited manufacturer warranty', 'Free shipping'),
(5, 2, 'Apple', 'MacBook Air M4 13', 'Apple MacBook Air 13-inch M4', 'Thin and quiet laptop with Apple M4 performance, excellent battery life, a sharp Liquid Retina display, MagSafe, and Thunderbolt ports for school and creative work.', JSON_ARRAY('Apple M4 chip', '13.6-inch Liquid Retina display', 'Fanless silent design', 'MagSafe charging', 'Two Thunderbolt 4 ports'), JSON_OBJECT('Display','13.6-inch Liquid Retina','Processor','Apple M4','Memory','16GB unified memory demo config','Storage','256GB SSD','Ports','MagSafe 3, 2x Thunderbolt 4, headphone jack','Best for','Students, travel, coding, office work'), 999.00, 1099.00, 4.9, 2204, 12, 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?auto=format&fit=crop&w=1000&q=80', 'https://www.apple.com/macbook-air/specs/', '1-year limited manufacturer warranty', 'Free 2-day demo shipping'),
