(8, 2, 'Lenovo', 'ThinkPad X1 Carbon', 'Lenovo ThinkPad X1 Carbon', 'Business laptop with a durable lightweight design, excellent keyboard, security features, and long battery life for professional users.', JSON_ARRAY('Legendary ThinkPad keyboard', 'Light carbon-fiber class chassis', 'Business security features', 'Long battery life', 'Thunderbolt connectivity'), JSON_OBJECT('Display','14-inch business display','Processor','Intel Core Ultra class','Memory','16GB demo config','Storage','512GB SSD','Security','Fingerprint and camera privacy features','Best for','Business and productivity'), 1399.00, 1649.00, 4.7, 533, 9, 'https://images.unsplash.com/photo-1588872657578-7efd1f1555ed?auto=format&fit=crop&w=1000&q=80', 'https://www.lenovo.com/us/en/c/laptops/thinkpad/thinkpadx1/', '3-year business-style demo warranty', 'Ships in 3 business days'),
