(10, 5, 'Samsung', 'Galaxy Tab S10+', 'Samsung Galaxy Tab S10+', 'Large Android tablet with AMOLED display, included-style S Pen experience, multitasking, and strong entertainment features.', JSON_ARRAY('Large AMOLED display', 'S Pen workflow', 'DeX-style multitasking', 'Quad speaker class audio', 'Thin premium body'), JSON_OBJECT('Display','12-inch AMOLED class','Processor','Flagship tablet processor class','Storage','256GB demo config','Input','S Pen support','Best for','Media, notes, and Android multitasking'), 999.99, 1099.99, 4.6, 386, 8, 'https://images.unsplash.com/photo-1561154464-82e9adf32764?auto=format&fit=crop&w=1000&q=80', 'https://www.samsung.com/us/tablets/', '1-year limited manufacturer warranty', 'Pickup available'),
