(13, 3, 'Bose', 'QuietComfort Ultra', 'Bose QuietComfort Ultra Headphones', 'Comfort-focused premium headphones with immersive audio, excellent noise cancellation, and plush over-ear fit for long listening sessions.', JSON_ARRAY('Immersive audio mode', 'Premium noise cancellation', 'Comfortable over-ear fit', 'Bluetooth multipoint', 'Travel case included'), JSON_OBJECT('Type','Over-ear ANC headphones','Battery','Up to 24 hours class','Charging','USB-C','Audio modes','Quiet, Aware, Immersion','Best for','Comfort and travel'), 429.00, 449.00, 4.7, 1298, 15, 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?auto=format&fit=crop&w=1000&q=80', 'https://www.bose.com/p/headphones/bose-quietcomfort-ultra-headphones/QCUH-HEADPHONEARN.html', '1-year limited manufacturer warranty', 'Free shipping'),
