(15, 4, 'Samsung', 'Galaxy Watch Ultra', 'Samsung Galaxy Watch Ultra', 'Rugged smartwatch with a bright display, durable build, fitness metrics, and Android-friendly health tracking.', JSON_ARRAY('Rugged watch design', 'Bright outdoor display', 'Fitness and sleep tracking', 'Water-resistant build', 'LTE-style adventure features'), JSON_OBJECT('Display','Outdoor bright AMOLED class','Battery','Multi-day class depending on mode','Health','Fitness, sleep, heart tracking','Compatibility','Android ecosystem','Best for','Outdoor Android users'), 649.99, 699.99, 4.6, 744, 11, 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&w=1000&q=80', 'https://www.samsung.com/us/watches/galaxy-watch-ultra/', '1-year limited manufacturer warranty', 'Free shipping'),
(16, 6, 'Nintendo', 'HEG-001', 'Nintendo Switch OLED Model', 'Hybrid game console with a vibrant 7-inch OLED screen, docked TV play, detachable Joy-Con controllers, and access to Nintendo exclusives.', JSON_ARRAY('7-inch OLED screen', 'TV, tabletop, and handheld modes', '64GB internal storage class', 'Dock with wired LAN port', 'Joy-Con controllers'), JSON_OBJECT('Display','7-inch OLED','Storage','64GB internal class','Modes','TV, tabletop, handheld','Connectivity','Wi-Fi and docked LAN','Best for','Nintendo games and portable play'), 349.99, 349.99, 4.8, 4022, 18, 'https://images.unsplash.com/photo-1578303512597-81e6cc155b3e?auto=format&fit=crop&w=1000&q=80', 'https://www.nintendo.com/us/gaming-systems/switch/tech-specs/', '1-year limited manufacturer warranty', 'Pickup available'),
