(18, 6, 'Microsoft', 'Xbox Series X', 'Xbox Series X', 'Powerful Xbox console with fast SSD storage, 4K gaming support, Game Pass access, and broad backward compatibility.', JSON_ARRAY('4K gaming class performance', 'Fast SSD storage', 'Quick Resume', 'Game Pass ready', 'Backward compatibility'), JSON_OBJECT('Storage','1TB SSD class','Resolution','Up to 4K gaming class','Controller','Xbox Wireless Controller','Subscription','Game Pass compatible','Best for','Xbox ecosystem and Game Pass'), 499.99, 499.99, 4.8, 3990, 12, 'https://images.unsplash.com/photo-1621259182978-fbf93132d53d?auto=format&fit=crop&w=1000&q=80', 'https://www.xbox.com/en-US/consoles/xbox-series-x', '1-year limited manufacturer warranty', 'Free shipping'),
(19, 7, 'Sony', 'ZV-E10 II', 'Sony ZV-E10 II Creator Camera', 'Compact interchangeable-lens camera for creators with strong video tools, flip screen, product showcase style shooting, and high-quality APS-C imaging.', JSON_ARRAY('APS-C interchangeable-lens camera', 'Creator-focused video tools', 'Flip-out screen', 'USB streaming support', 'Compact body'), JSON_OBJECT('Sensor','APS-C class','Lens mount','Sony E-mount','Video','4K creator video class','Screen','Vari-angle display','Best for','YouTube, streaming, and content creation'), 999.99, 1099.99, 4.6, 284, 6, 'https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&w=1000&q=80', 'https://electronics.sony.com/imaging/interchangeable-lens-cameras/aps-c/p/zve10m2-b', '1-year limited manufacturer warranty', 'Ships in 2 business days'),
